module RefModule(
    input clk,
    input wr, 
    input[31:0] in_data,

    output[31:0] out_data
);reg[31:0] data = 32'h00000000;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
    if(wr)
        data <= in_data;
end
assign out_data = data;
endmodule
